import React from 'react';

export const PopperDrillingContext = React.createContext<{
  referenceHidden: boolean;
  getScrollParents: () => Array<Element | Window | VisualViewport>;
} | null>(null);
export const { Provider: PopperDrillingContextProvider } = PopperDrillingContext;
export function usePopperDrillingContext() {
  return React.useContext(PopperDrillingContext);
}

if (__DEV__) {
  PopperDrillingContext.displayName = 'PopperDrillingContext';
}
